PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?series ?attendance
WHERE {
  ?series wdt:P31 wd:Q1363275 ;
          wdt:P1346 wd:Q334634 ;
          wdt:P1346 wd:Q650840 ;
          wdt:P1425 ?attendance .
}
ORDER BY ?attendance
LIMIT 2 OFFSET 1

